@use "variables" as *;

// Media queries
@mixin mobile {
  @media (max-width: $bpMobile) {
    @content;
  }
}

@mixin tablet {
  @media (max-width: $bpTablet) {
    @content;
  }
}

@mixin tabletUp {
  @media (min-width: ($bpTablet + 1)) {
    @content;
  }
}

@mixin desktop {
  @media (min-width: $bpDesktop) {
    @content;
  }
}

@mixin wide {
  @media (min-width: $bpWide) {
    @content;
  }
}

// Glass morphism
@mixin glass {
  background: $glassBg;
  backdrop-filter: blur($glassBlur);
  -webkit-backdrop-filter: blur($glassBlur);
  border: 1px solid $glassBorder;
}

@mixin glassHover {
  background: $glassBgHover;
  border-color: $glassBorderHover;
}

// Container
@mixin container {
  width: 100%;
  max-width: $maxWidth;
  margin: 0 auto;
  padding: 0 $space6;

  @include tablet {
    padding: 0 $space4;
  }
}

// Truncate
@mixin truncate($lines: 1) {
  @if $lines == 1 {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  } @else {
    display: -webkit-box;
    -webkit-line-clamp: $lines;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
}

// Focus ring
@mixin focusRing {
  outline: 2px solid $accentPurple;
  outline-offset: 2px;
}

// Scrollbar
@mixin customScrollbar {
  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: $textMuted;
    border-radius: $radiusFull;
  }
}

