import { useState, useEffect, useCallback } from "react";
import { apiFetch } from "@/lib/api";
import type { SearchResult, Candidate } from "@rearden/types";

interface SearchResultWithCandidate extends SearchResult {
  candidate: Candidate;
}

export function useSearch() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResultWithCandidate[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const search = useCallback(async (searchQuery: string) => {
    if (!searchQuery.trim()) {
      setLoading(true);
      try {
        const response = await apiFetch<{ success: boolean; data: Candidate[] }>("/candidates");
        setResults(
          response.data.map((candidate) => ({
            candidateId: candidate.id,
            score: 0,
            matchReason: "Featured candidate",
            candidate,
          }))
        );
        setError(null);
      } catch (e) {
        setError(e instanceof Error ? e.message : "Unknown error");
      } finally {
        setLoading(false);
      }
      return;
    }

    setLoading(true);
    try {
      const response = await apiFetch<{ success: boolean; data: SearchResultWithCandidate[] }>(
        "/search",
        {
          method: "POST",
          body: JSON.stringify({ query: searchQuery }),
        }
      );
      setResults(response.data);
      setError(null);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Unknown error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      search(query);
    }, 400);

    return () => clearTimeout(timer);
  }, [query, search]);

  return { query, setQuery, results, loading, error };
}

