import { motion } from "motion/react";
import type { Candidate } from "@rearden/types";
import { SkillTag } from "@/components/SkillTag/SkillTag";
import { ScoreBadge } from "@/components/ScoreBadge/ScoreBadge";
import styles from "./CandidateCard.module.scss";

interface CandidateCardProps {
  candidate: Candidate;
  score?: number;
  matchReason?: string;
  onClick?: () => void;
}

export function CandidateCard({
  candidate,
  score,
  matchReason,
  onClick,
}: CandidateCardProps) {
  const displaySkills = candidate.skills.slice(0, 4);

  return (
    <motion.div
      className={styles.card}
      whileHover={{ y: -4 }}
      onClick={onClick}
      role={onClick ? "button" : undefined}
      tabIndex={onClick ? 0 : undefined}
    >
      <div className={styles.thumbnail}>
        {candidate.thumbnailUrl ? (
          <img src={candidate.thumbnailUrl} alt={candidate.name} />
        ) : (
          <div className={styles.placeholder} />
        )}
        {score !== undefined && (
          <div className={styles.scoreBadge}>
            <ScoreBadge score={score} />
          </div>
        )}
      </div>

      <div className={styles.content}>
        <h3 className={styles.name}>{candidate.name}</h3>
        <p className={styles.title}>{candidate.title}</p>
        <p className={styles.location}>{candidate.location}</p>

        <div className={styles.skills}>
          {displaySkills.map((skill) => (
            <SkillTag key={skill} skill={skill} size="sm" />
          ))}
        </div>

        {matchReason && (
          <p className={styles.matchReason}>{matchReason}</p>
        )}
      </div>
    </motion.div>
  );
}

