import { Hono } from "hono";
import type { ApiResponse, SearchQuery, SearchResult } from "@rearden/types";
import { mockCandidates } from "../data/mockCandidates.js";
import { searchCandidates } from "../lib/searchEngine.js";

export const searchRoutes = new Hono();

// POST /api/search - Search candidates
searchRoutes.post("/", async (c) => {
  try {
    const body = (await c.req.json()) as SearchQuery;
    const { query, filters } = body;

    // Track search time
    const startTime = Date.now();

    // Artificial delay to simulate processing
    await new Promise((resolve) => setTimeout(resolve, 500));

    // Perform search
    const scoredCandidates = searchCandidates(mockCandidates, query, filters);

    const endTime = Date.now();
    const searchTimeMs = endTime - startTime;

    // Build response
    const results: (SearchResult & { candidate: typeof scoredCandidates[0]["candidate"] })[] =
      scoredCandidates.map((sc) => ({
        candidateId: sc.candidate.id,
        score: sc.score,
        matchReason: sc.matchReason,
        candidate: sc.candidate,
      }));

    return c.json<ApiResponse>({
      success: true,
      data: {
        results,
        query,
        totalCandidates: mockCandidates.length,
        searchTimeMs,
      },
    });
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Invalid search request",
      },
      400
    );
  }
});

