import { useNavigate } from "react-router-dom";
import { motion } from "motion/react";
import { PageTransition } from "@/components/PageTransition/PageTransition";
import { Button } from "@/components/Button/Button";
import { Logo } from "@/components/Logo/Logo";
import styles from "./Landing.module.scss";

const features = [
  {
    icon: "M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z",
    title: "Video-First Profiles",
    description: "Candidates showcase their skills through short video introductions, giving you a real sense of who they are.",
  },
  {
    icon: "M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z",
    title: "AI-Powered Search",
    description: "Describe your ideal candidate in natural language and our AI finds the best matches instantly.",
  },
  {
    icon: "M13 10V3L4 14h7v7l9-11h-7z",
    title: "Lightning Fast",
    description: "Skip the resume pile. Watch candidate videos, assess fit, and reach out — all in minutes.",
  },
];

const containerVariants = {
  hidden: {},
  visible: {
    transition: { staggerChildren: 0.15 },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 30 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: "easeOut" } },
};

export function Landing() {
  const navigate = useNavigate();

  return (
    <PageTransition>
      <div className={styles.landing}>
        <section className={styles.hero}>
          <div className={styles.heroContent}>
            <motion.div
              className={styles.badge}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5 }}
            >
              The future of hiring
            </motion.div>

            <motion.h1
              className={styles.heading}
              initial={{ opacity: 0, y: 40 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.7, type: "spring", stiffness: 100 }}
            >
              Hire talent through
              <span className={styles.gradient}> video</span>, not
              <span className={styles.strikethrough}> resumes</span>
            </motion.h1>

            <motion.p
              className={styles.subheading}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.2 }}
            >
              Rearden connects recruiters with candidates through AI-powered video profiles.
              See beyond the resume — discover personality, communication, and culture fit.
            </motion.p>

            <motion.div
              className={styles.ctas}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.4 }}
            >
              <Button variant="primary" size="lg" onClick={() => navigate("/search")}>
                Start Searching
              </Button>
              <Button variant="secondary" size="lg" onClick={() => navigate("/register")}>
                Join as Candidate
              </Button>
            </motion.div>
          </div>

          <div className={styles.heroGlow} />
        </section>

        <section className={styles.features}>
          <motion.div
            className={styles.featuresGrid}
            variants={containerVariants}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-100px" }}
          >
            {features.map((feature) => (
              <motion.div
                key={feature.title}
                className={styles.featureCard}
                variants={itemVariants}
              >
                <div className={styles.featureIcon}>
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d={feature.icon} />
                  </svg>
                </div>
                <h3 className={styles.featureTitle}>{feature.title}</h3>
                <p className={styles.featureDescription}>{feature.description}</p>
              </motion.div>
            ))}
          </motion.div>
        </section>

        <section className={styles.stats}>
          <motion.div
            className={styles.statsGrid}
            variants={containerVariants}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true }}
          >
            {[
              { value: "500+", label: "Video Profiles" },
              { value: "85%", label: "Faster Hiring" },
              { value: "3x", label: "Better Match Rate" },
            ].map((stat) => (
              <motion.div key={stat.label} className={styles.stat} variants={itemVariants}>
                <span className={styles.statValue}>{stat.value}</span>
                <span className={styles.statLabel}>{stat.label}</span>
              </motion.div>
            ))}
          </motion.div>
        </section>

        <section className={styles.cta}>
          <motion.div
            className={styles.ctaContent}
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            <Logo size="lg" />
            <h2 className={styles.ctaHeading}>Ready to transform your hiring?</h2>
            <Button variant="primary" size="lg" onClick={() => navigate("/search")}>
              Explore Candidates
            </Button>
          </motion.div>
        </section>
      </div>
    </PageTransition>
  );
}

@use "../../styles/variables" as *;
@use "../../styles/mixins" as *;

.landing {
  min-height: 100vh;
}

// Hero
.hero {
  position: relative;
  padding: $space20 0 $space16;
  overflow: hidden;

  @include tablet {
    padding: $space12 0 $space10;
  }
}

.heroContent {
  @include container;
  text-align: center;
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.badge {
  display: inline-block;
  padding: $space2 $space4;
  background: rgba($accentPurple, 0.15);
  border: 1px solid rgba($accentPurple, 0.3);
  border-radius: $radiusFull;
  font-size: $fontSize13;
  color: $accentPurpleLight;
  font-weight: 500;
  letter-spacing: 0.5px;
  margin-bottom: $space8;
}

.heading {
  font-size: $fontSize64;
  font-weight: 800;
  line-height: 1.1;
  max-width: 800px;
  letter-spacing: -1.5px;

  @include tablet {
    font-size: $fontSize40;
  }

  @include mobile {
    font-size: $fontSize32;
  }
}

.gradient {
  background: linear-gradient(135deg, $accentPurple, $accentTeal);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.strikethrough {
  text-decoration: line-through;
  color: $textMuted;
  text-decoration-color: $textMuted;
}

.subheading {
  font-size: $fontSize18;
  color: $textSecondary;
  max-width: 600px;
  line-height: 1.6;
  margin-top: $space6;

  @include tablet {
    font-size: $fontSize16;
  }
}

.ctas {
  display: flex;
  gap: $space4;
  margin-top: $space10;

  @include mobile {
    flex-direction: column;
    width: 100%;
    max-width: 300px;
  }
}

.heroGlow {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, rgba($accentPurple, 0.12) 0%, transparent 70%);
  pointer-events: none;
}

// Features
.features {
  padding: $space16 0;
}

.featuresGrid {
  @include container;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: $space6;

  @include tablet {
    grid-template-columns: 1fr;
    gap: $space4;
  }
}

.featureCard {
  @include glass;
  border-radius: $radiusLg;
  padding: $space8;
  transition: border-color $transitionBase, background $transitionBase;

  &:hover {
    @include glassHover;
  }
}

.featureIcon {
  width: 48px;
  height: 48px;
  border-radius: $radiusMd;
  background: rgba($accentPurple, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  color: $accentPurple;
  margin-bottom: $space5;
}

.featureTitle {
  font-size: $fontSize18;
  font-weight: 600;
  margin-bottom: $space3;
}

.featureDescription {
  font-size: $fontSize14;
  color: $textSecondary;
  line-height: 1.6;
}

// Stats
.stats {
  padding: $space12 0;
}

.statsGrid {
  @include container;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: $space6;
  text-align: center;

  @include tablet {
    grid-template-columns: 1fr;
    gap: $space8;
  }
}

.stat {
  display: flex;
  flex-direction: column;
  gap: $space2;
}

.statValue {
  font-size: $fontSize48;
  font-weight: 800;
  background: linear-gradient(135deg, $accentPurple, $accentTeal);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;

  @include tablet {
    font-size: $fontSize32;
  }
}

.statLabel {
  font-size: $fontSize16;
  color: $textSecondary;
}

// Bottom CTA
.cta {
  padding: $space16 0 $space20;
}

.ctaContent {
  @include container;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: $space6;
}

.ctaHeading {
  font-size: $fontSize32;
  font-weight: 700;

  @include tablet {
    font-size: $fontSize24;
  }
}

