@use "../../styles/variables" as *;
@use "../../styles/mixins" as *;

.card {
  @include glass;
  border-radius: $radiusLg;
  overflow: hidden;
  cursor: pointer;
  transition: all $transitionBase;

  &:hover {
    box-shadow: $shadowMd;
    @include glassHover;

    .thumbnail img {
      transform: scale(1.05);
    }
  }

  &:focus-visible {
    @include focusRing;
  }
}

.thumbnail {
  position: relative;
  width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
  background: $bgSurface;

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform $transitionSlow;
  }
}

.placeholder {
  width: 100%;
  height: 100%;
  background: linear-gradient(135deg, $bgSurface 0%, $bgElevated 100%);
}

.scoreBadge {
  position: absolute;
  top: $space3;
  right: $space3;
}

.content {
  padding: $space4;
  display: flex;
  flex-direction: column;
  gap: $space2;
}

.name {
  font-size: $fontSize16;
  font-weight: 600;
  color: $textPrimary;
  margin: 0;
  @include truncate(1);
}

.title {
  font-size: $fontSize14;
  color: $textSecondary;
  margin: 0;
  @include truncate(1);
}

.location {
  font-size: $fontSize13;
  color: $textMuted;
  margin: 0;
  @include truncate(1);
}

.skills {
  display: flex;
  flex-wrap: wrap;
  gap: $space2;
  margin-top: $space2;
  overflow: hidden;
  max-height: 24px;
}

.matchReason {
  font-size: $fontSize13;
  color: $textSecondary;
  margin: $space2 0 0;
  @include truncate(2);
}

