import { Hono } from "hono";
import type { ApiResponse, Candidate } from "@rearden/types";
import { mockCandidates } from "../data/mockCandidates.js";

export const candidateRoutes = new Hono();

// In-memory storage (starts with mock data)
let candidates: Candidate[] = [...mockCandidates];

// GET /api/candidates - Get all candidates
candidateRoutes.get("/", (c) => {
  return c.json<ApiResponse<Candidate[]>>({
    success: true,
    data: candidates,
  });
});

// GET /api/candidates/:id - Get candidate by ID
candidateRoutes.get("/:id", (c) => {
  const id = c.req.param("id");
  const candidate = candidates.find((cand) => cand.id === id);

  if (!candidate) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Candidate not found",
      },
      404
    );
  }

  return c.json<ApiResponse<Candidate>>({
    success: true,
    data: candidate,
  });
});

// POST /api/candidates - Create new candidate
candidateRoutes.post("/", async (c) => {
  try {
    const body = await c.req.json();

    // Generate new candidate with ID and timestamps
    const now = new Date().toISOString();
    const newCandidate: Candidate = {
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now,
      role: "candidate" as const,
      resume: null,
      skills: [],
      experience: 0,
      videoUrl: null,
      thumbnailUrl: null,
      location: "",
      title: "",
      bio: "",
      availability: "immediate",
      ...body,
    };

    candidates.push(newCandidate);

    return c.json<ApiResponse<Candidate>>(
      {
        success: true,
        data: newCandidate,
      },
      201
    );
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Invalid request body",
      },
      400
    );
  }
});

