### 9. Theme Context and State Management

**File: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\contexts\ThemeContext.tsx` (NEW)**

Use a `data-theme` attribute on `<html>` for CSS switching, with React context for UI state only.

```tsx
import { createContext, useContext, useEffect, useState, type ReactNode } from "react";

type Theme = "y2k" | "purple-night";

interface ThemeContextValue {
  theme: Theme;
  setTheme: (theme: Theme) => void;
}

const STORAGE_KEY = "rearden-theme";
const DEFAULT_THEME: Theme = "y2k";

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    return (stored === "y2k" || stored === "purple-night") ? stored : DEFAULT_THEME;
  });

  const setTheme = (next: Theme) => {
    setThemeState(next);
    localStorage.setItem(STORAGE_KEY, next);
    document.documentElement.setAttribute("data-theme", next);
  };

  // Set initial attribute on mount
  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
  }, []);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used within ThemeProvider");
  return ctx;
}
```

**Why `data-theme` on `<html>` instead of a React-only approach:** CSS custom properties cascade from the DOM. Setting `data-theme` on `documentElement` means the CSS custom properties defined in `_tokens.scss` under `[data-theme="..."]` selectors take effect globally and instantly. No class manipulation, no style injection, no React re-renders needed for the theme change itself -- only the dropdown UI needs React state.

**Flash-of-wrong-theme prevention:** Add a small inline script to `index.html` that reads `localStorage` and sets `data-theme` before React hydrates:

**File: `C:\Users\yakik\Documents\projects\rearden\apps\web\index.html` (MODIFY)**

```html
<script>
  (function() {
    var t = localStorage.getItem('rearden-theme');
    if (t === 'y2k' || t === 'purple-night') {
      document.documentElement.setAttribute('data-theme', t);
    }
  })();
</script>
```

